<?php $referrer = App\Models\User::firstOrCreate(['email' => 'ref1@test.com'], ['name' => 'Ref One', 'password' => bcrypt('123'), 'role' => 'client', 'balance' => 0, 'referral_code' => 'T-REF-1']); $referred = App\Models\User::firstOrCreate(['email' => 'ref2@test.com'], ['name' => 'Ref Two', 'password' => bcrypt('123'), 'role' => 'client', 'balance' => 0]); App\Models\Referral::firstOrCreate(['referrer_id' => $referrer->id, 'referred_id' => $referred->id]); echo 'Linked. '; $service = app(App\Services\ReferralService::class); $service->awardCommission($referred, 200, 'Test', null, 'transaction'); echo 'Created pending commission for  top-up. '; $earning = App\Models\ReferralEarning::where('referrer_id', $referrer->id)->latest()->first(); echo 'Status: ' . $earning->status . ', Amount: ' . $earning->amount . '. '; $earning->update(['created_at' => now()->subDays(15)]); echo '15 days passed... '; Artisan::call('referral:process-pending'); $referrer->refresh(); $earning->refresh(); echo 'Final Status: ' . $earning->status . ', New Balance: ' . $referrer->balance . '. ';
